scwin.btn_retrieve_onClick = async function (e) {
  ds_LkStepNo2.clearFilter();
  // $c.gus.cfEnableObj(btn_create);

  if (!(await $c.gus.cfValidate($p, [ed_cvsslMgntNo, acb_expImpClsCd]))) {
    return;
  }
  dma_condition.set("cvsslWrkPlCls", "P");
  dma_condition.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());
  dma_condition.set("expImpClsCd", acb_expImpClsCd.getValue());
  await $c.sbm.execute($p, sbm_condition);
};

